  const saveCheck=async()=>{if(healthSaving)return; const weightValue=String(form.weight??"").trim(); const kcalValue=String(form.kcal??"").trim(); const stepsValue=String(form.steps??"").trim(); const parsedWeight=weightValue===""?null:Number(weightValue); if(weightValue!==""&&(!Number.isFinite(parsedWeight)||parsedWeight<=0)){alert("체중은 0보다 큰 숫자로 입력해주세요.");return;} if(!weightValue&&!kcalValue&&!stepsValue){alert("저장할 건강 기록을 입력해주세요.");return;} setHealthSaving(true); try{assertOwnMember(); const dateKey=form.date||today; await saveMemberHealthInputs(profile.id,dateKey,{weight:weightValue,kcal:kcalValue,steps:stepsValue}); if(parsedWeight){setBody(prev=>({...(prev||{}),records:upsertBodyRecord(prev?.records||[],{id:`member_${dateKey}`,date:dateKey,weight:parsedWeight,note:"회원앱 직접 입력"})}));} setForm(f=>({...f,weight:"",kcal:"",steps:""})); await load(); alert("건강관리 기록이 저장됐어요");}catch(e){console.error("[MemberApp] health save failed",e); alert(e?.message||"건강관리 기록 저장에 실패했습니다.");}finally{setHealthSaving(false);}};
