// VAS_TIMING 상수는 빠른 통증 입력 UI의 SITUATIONS 객체로 통합됨
function getMuscleLabel(id) {
  return [...FRONT_MUSCLES, ...BACK_MUSCLES].find(m => m.id === id)?.label || id;
}

function generateAutoSummary(bodyMap, posture, mobility) {
  try {
    const tightList = Object.entries(bodyMap||{}).filter(([,v])=>v==="tight").map(([k])=>getMuscleLabel(k));
    const weakList  = Object.entries(bodyMap||{}).filter(([,v])=>v==="weak").map(([k])=>getMuscleLabel(k));
    const issues = [];
    if (tightList.length) issues.push("과긴장/타이트: "+tightList.join(", "));
    if (weakList.length)  issues.push("기능저하/약화: "+weakList.join(", "));
    // posture 값이 배열이거나 {B,L,R} 객체 모두 처리
    const postureIssues = (Array.isArray(POSTURE_ITEMS)?POSTURE_ITEMS:[]).flatMap(item=>{
      const val = (posture||{})[item.key];
      if (!val) return [];
      if (Array.isArray(val)) return val.map(v=>item.label+" "+v);
      // {B:[], L:[], R:[]} 형태
      const all = [...(val.B||[]), ...(val.L||[]).map(v=>"(좌)"+v), ...(val.R||[]).map(v=>"(우)"+v)];
      return all.map(v=>item.label+" "+v);
    });
    if (postureIssues.length) issues.push(...postureIssues);
    const mobIssues = (Array.isArray(MOBILITY_ITEMS)?MOBILITY_ITEMS:[])
      .filter(item=>{
        const v=(mobility||{})[item.key];
        const val = typeof v==="string" ? v : (v?.B || "");
        return val==="제한"||val==="제한 있음"||val==="약함"||val==="있음";
      })
      .map(item=>item.label);
    if (mobIssues.length) issues.push("기능 제한: "+mobIssues.join(", "));
    if (!issues.length) return "";
    const recs = [];
    if (tightList.some(l=>l.includes("흉근")||l.includes("전면삼각"))) recs.push("흉근 릴리즈 + 후면 어깨 활성화");
    if (weakList.some(l=>l.includes("둔근"))) recs.push("둔근 활성화 운동");
    if (weakList.some(l=>l.includes("척추기립근")||l.includes("승모근"))) recs.push("코어 안정화 + 중부 승모근 강화");
    return issues.join(". ")+"."+(recs.length?" 권장 루틴: "+recs.join(" → "):"");
  } catch(e) {
    console.error("[generateAutoSummary] error:", e);
    return "";
  }
}


function normalizeAssessmentRecords(rawRecords = []) {
  return (Array.isArray(rawRecords) ? rawRecords : []).map(r => {
    if (r.muscleItems !== undefined) return r;

    const muscleItems = [];
    if (r.bodyMap && typeof r.bodyMap === "object") {
      Object.entries(r.bodyMap).forEach(([k, v]) => {
        const parts = k.split("_");
        const side  = ["좌","우","양"].includes(parts[parts.length-1]) ? parts[parts.length-1] : "양";
        const name  = parts.slice(0, -1).join("_") || k;
        if (v === "tight" || v === "weak") {
          muscleItems.push({ id: Date.now()+Math.random(), name, side, type: v });
        }
      });
    }

    const postureList = [];
    if (r.posture && typeof r.posture === "object") {
      Object.values(r.posture).forEach(v => {
        const opts = Array.isArray(v) ? v :
          [...(v.B||[]), ...(v.L||[]).map(x=>"(좌)"+x), ...(v.R||[]).map(x=>"(우)"+x)];
        if (opts.length > 0) postureList.push(...opts.filter(Boolean));
      });
    }

    const painList = Array.isArray(r.painList) ? [...r.painList] : [];
    if (r.fParts && r.fParts.length > 0 && painList.length === 0) {
      r.fParts.forEach(part => {
        painList.push({ id: Date.now()+Math.random(), part, side: r.fSide||"양측",
          vas: r.fVas||0, situation: (r.fSituations||[])[0]||"", memo: r.fMemo||"" });
      });
    }

    return {
      ...r,
      id: r.id || `a${Date.now()}_${Math.random().toString(36).slice(2)}`,
      muscleItems,
      postureList,
      mobility: r.mobility || {},
      painList,
      evalMemo: r.evalMemo || r.fastMemo || r.summary || "",
      _migrated: true,
    };
  });
}

function loadLocalAssessmentRecords(memberId) {
  try {
    return normalizeAssessmentRecords(JSON.parse(localStorage.getItem("assess_"+memberId)||"[]"));
  } catch {
    return [];
  }
}

function sortAssessments(records = []) {
  return [...records].sort((a,b) => String(b.date || "").localeCompare(String(a.date || "")) || String(b.savedAt || "").localeCompare(String(a.savedAt || "")));
}

function mergeAssessments(...groups) {
  const byId = new Map();
  groups.flat().forEach(record => {
    if (!record) return;
    const id = record.id || `a${Date.now()}_${Math.random().toString(36).slice(2)}`;
    byId.set(id, { ...record, id });
  });
  return sortAssessments([...byId.values()]);
}

